// Maps the current UTC hour to an audience region plus a daily send cap.
// Ranges are non-overlapping so each trigger hits exactly one group.
const hour = new Date().getUTCHours();
let group, daily_limit;

if (hour >= 9 && hour < 13) {
  // EU & UK working hours (morning Europe)
  group = 'EU_UK';
  daily_limit = 45;
} else if (hour >= 14 && hour < 20) {
  // North America working hours (morning/midday NA)
  group = 'NA';
  daily_limit = 90;
} else {
  // Remaining hours cover Australia / Asia-Pacific
  group = 'AU';
  daily_limit = 15;
}

return [{ json: { group, daily_limit } }];

const group = $('Determine Group').first().json.group;
const daily_limit = $('Determine Group').first().json.daily_limit;

const countryGroups = {
  'Austria': 'EU_UK', 'Belgium': 'EU_UK', 'France': 'EU_UK',
  'Germany': 'EU_UK', 'Italy': 'EU_UK', 'Netherlands': 'EU_UK',
  'Norway': 'EU_UK', 'Spain': 'EU_UK', 'Sweden': 'EU_UK',
  'Switzerland': 'EU_UK', 'United Kingdom': 'EU_UK',
  'Canada': 'NA', 'United States': 'NA',
  'Australia': 'AU'
};

const filtered = items.filter(item => {
  const country   = (item.json['Country'] || '').trim();
  const emailSent = (item.json['email_sent'] || '').toString().trim();
  const email     = (item.json['Email'] || '').trim();
  return (
    countryGroups[country] === group &&
    emailSent === '' &&
    email.includes('@')
  );
});

return filtered.slice(0, daily_limit);
